from sbxcpp.space import Space, Tilemap, BodyID
from vmath import vec3, vec3i
from random import Random

BASE_TILE = 1
WALL_TILE = 2

def pretty_vec3(v: vec3) -> str:
    return f"({v.x:8.4f}, {v.y:8.4f}, {v.z:8.4f})"

class Playground:
    def on_pair_add(self, a: BodyID, b: BodyID, xzl: vec3i, normal: vec3, max_sep: float):
        print(f"on_pair_add: a={a}, b={b}, xzl={xzl}, normal={normal}, max_sep={max_sep}")
    def on_pair_remove(self, a: BodyID, b: BodyID, xzl: vec3i):
        print(f"on_pair_remove: a={a}, b={b}, xzl={xzl}")

    def __init__(self):
        tilemap = Tilemap(20, 20)
        self.space = Space(tilemap, 10, self)
    
        rnd = Random(17)
        # generate
        for x in range(tilemap.width):
            for y in range(tilemap.height):
                tilemap.set(x, y, 0, BASE_TILE)
                if rnd.random() < 0.1:
                    tilemap.set(x, y, 1, WALL_TILE)
        
        self.hero = self.space.create_body(3, vec3.ONE * 0.5, 0)
        self.space.teleport_body(self.hero, vec3(1, 0.4+2, 1))
        self.space.gravity = vec3(0, -9.81, 0)

        tile_body = self.space.create_body(0, vec3.ONE * 0.5, 0)
        self.space.teleport_body(tile_body, vec3(0, -0.5, 0))
        self.space.register_tile_body(BASE_TILE, tile_body)

        tile_body = self.space.create_body(0, vec3.ONE * 0.5, 0.8)
        self.space.teleport_body(tile_body, vec3(0, 0.5, 0))
        self.space.register_tile_body(WALL_TILE, tile_body)

    def move_hero_and_step(self, vel_x: float, vel_z: float, delta: float):
        pos = self.space.body_get_position(self.hero)
        vel_y = self.space.body_get_velocity(self.hero).y
        self.space.body_set_velocity(self.hero, vec3(vel_x, vel_y, vel_z))
        self.space.step(delta)
        return pos
    
    def debug_info(self) -> str:
        lines = []
        position = self.space.body_get_position(self.hero)
        chunk_index = self.space.body_get_chunk_index(self.hero)
        velocity = self.space.body_get_velocity(self.hero)
        lines.append(f"position: {pretty_vec3(position)}")
        lines.append(f"chunk index: {chunk_index}")
        lines.append(f"velocity: {pretty_vec3(velocity)}")
        return "\n".join(lines)
    

instance = Playground()
